mapper.select:
SELECT CAT_ID, TITLE, DEPT, SEQ, CREATED_AT
FROM LS_CATEGORY
WHERE CAT_ID = #{catId}

SELECT TASK_ID, CAT_ID, TITLE, SEQ, CREATED_AT
FROM LS_TASK
WHERE CAT_ID = #{catId}
  AND TASK_ID = #{taskId}

SELECT GOAL_ID, TITLE, SEQ, CREATED_AT
FROM CT_GOAL
WHERE GOAL_ID = #{goalId}

SELECT IND_ID, GOAL_ID, TITLE, SEQ, CREATED_AT
FROM CT_INDICATOR
WHERE IND_ID = #{indId}

SELECT IND_ID, NAME, DEPT, QUANT, T1, T2, T3, FORECAST, PLAN, UPDATED_AT
FROM CT_INDICATOR_DETAIL
WHERE IND_ID = #{indId}

SELECT SUB_TASK_ID, IND_ID, TITLE
FROM CT_SUB_TASK
WHERE SUB_TASK_ID = #{subTaskId}

SELECT IND_ID AS "id", IND_LABEL AS "label"
FROM ACT_INDICATOR
WHERE ACT_ID = #{actId}
